     1	// Re-export the Rhino-generated model schemas as friendly, fully-required types.
     2	// The generator emits everything as optional (`field?:`) because the source is
     3	// an OpenAPI-ish schema; we tighten them here for nicer DX on the consumer side.
     4	import type { components } from './types/rhino.d.ts';
     5	
     6	type Required<T> = { [K in keyof T]-?: T[K] };
     7	
     8	export type Organization = Required<components['schemas']['Organization']>;
     9	export type Role         = Required<components['schemas']['Role']>;
    10	export type Blog         = Required<components['schemas']['Blog']>;
    11	export interface User {
    12	  id: number;
    13	  name: string;
    14	  email: string;
    15	  created_at: string;
    16	  updated_at: string;
    17	}
    18	export interface UserRole {
    19	  id: number;
    20	  user_id: number;
    21	  role_id: number;
    22	  organization_id: number;
    23	  created_at: string;
    24	  updated_at: string;
    25	}
    26	export type Comment      = Required<components['schemas']['Comment']>;
    27	export type Label        = Required<components['schemas']['Label']>;
    28	export type Project      = Required<components['schemas']['Project']>;
    29	export type Task         = Required<components['schemas']['Task']>;
    30	
    31	// Convenience types for relations populated via ?include=
    32	export type ProjectWithTasks    = Project & { tasks?: Task[] };
    33	export type TaskWithAssignee    = Task & { assignee?: User };
    34	export type CommentWithAuthor   = Comment & { user?: User };
